// Reusable DataProject extractor. Body: {id, dpHost, fedcode, country, comps:[ids]}.
// Defaults target Ukraine (uvf-web). dpHost = subdomain before .dataproject.com.
const body=($('Webhook').first().json.body)||{};
const PROFILES={
  UKR:{id:'ubgjkrp9ofl0wxy',dpHost:'uvf-web',country:'Ukraine',comps:[162,163,164,165,166,167,168,169,170,181,182,171,172,173,174,175,176,177,178,179,180]},
  ALB:{id:'rusimnfot1yulwz',dpHost:'fshv-web',country:'Albania',comps:[108,114,115,116,117,122]}
};
const fedcode=(body.fedcode||'UKR').toUpperCase();
const prof=PROFILES[fedcode]||{};
const fedId=body.id||prof.id;
const dpHost=body.dpHost||prof.dpHost;
const country=body.country||prof.country||'';
const comps=(body.comps&&body.comps.length?body.comps:prof.comps)||[];
return comps.map(c=>({json:{comp:c,fedId,dpHost,country,fedcode}}));

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const {comp,fedId,dpHost,country,fedcode}=$json;
const now=new Date().toISOString();
const findClub=async(k)=>{const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:"(dedup_key='"+k+"')",perPage:1},headers:pbH,json:true});return (r.items&&r.items[0])||null;};
let html='';
try{html=await this.helpers.httpRequest({method:'GET',url:'https://'+dpHost+'.dataproject.com/CompetitionTeamSearch.aspx?ID='+comp,headers:{'User-Agent':'Mozilla/5.0'}});}catch(e){return [{json:{comp,error:'fetch:'+e.message}}];}
if(typeof html!=='string') html=String(html);
// team name lives in the logo img title; team id in TeamLogo_<id>.jpg within the same img tag
const decode=(s)=>String(s).replace(/&quot;/g,'"').replace(/&#0?39;/g,"'").replace(/&apos;/g,"'").replace(/&amp;/g,'&').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&#(\d+);/g,(m,n)=>String.fromCharCode(+n));
const re=/title="([^"]+)"[^>]*TeamLogo_(\d+)\.jpg/g; let m; const seen={}; const teams=[];
while((m=re.exec(html))!==null){const name=decode(m[1]).replace(/\s+/g,' ').trim(); const tid=m[2]; if(!name||seen[tid])continue; seen[tid]=1; teams.push({tid,name});}
let created=0;
for(const t of teams){ const dedup=fedcode+':'+t.tid; const base={federation:fedId,name:t.name,country,source_url:'https://'+dpHost+'.dataproject.com/CompetitionTeamSearch.aspx?ID='+comp,source_club_id:t.tid,dedup_key:dedup,last_scraped:now};
  try{ try{await this.helpers.httpRequest({method:'POST',url:PB_URL+'/api/collections/clubs/records',headers:pbH,body:Object.assign({},base,{website_source:'none',status:'new'}),json:true});created++;}
    catch(e){const ex=await findClub(dedup); if(ex){await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/clubs/records/'+ex.id,headers:pbH,body:base,json:true});}else throw e;} }
  catch(e){continue;}
}
return [{json:{comp,teams:teams.length,created}}];

const PB_URL=($('Config').first().json.pbUrl||'').replace(/\/+$/,'');
const token=$('PB Auth').first().json.token; const pbH={Authorization:token};
const body=($('Webhook').first().json.body)||{};
const fedId=body.id||'ubgjkrp9ofl0wxy';
const r=await this.helpers.httpRequest({method:'GET',url:PB_URL+'/api/collections/clubs/records',qs:{filter:'federation="'+fedId+'"',perPage:1},headers:pbH,json:true});
const n=r.totalItems||0;
await this.helpers.httpRequest({method:'PATCH',url:PB_URL+'/api/collections/federations/records/'+fedId,headers:pbH,body:{status:(n>0?'scraped':'needs_review'),club_count:n,last_scraped:new Date().toISOString()},json:true});
return [{json:{ok:true,clubs:n}}];
